import os

def load_templates():
    template_dir = "templates"  # Bug: relative to CWD, not to project
    templates = {}
    for fname in os.listdir(template_dir):
        if fname.endswith('.txt'):
            with open(os.path.join(template_dir, fname)) as f:
                templates[fname] = f.read()
    return templates
